def is_generator(g, p):
 # Check if g generates Zp*
 # Order should be p-1
 if pow(g, p-1, p) != 1:
 return False
 # Check no smaller exponent gives 1
 factors = prime_factors(p-1)
 for factor in factors:
 if pow(g, (p-1)//factor, p) == 1:
 return False
 return True

# Example: Find generators of Z11*
prime = 11
for g in range(2, prime):
 if is_generator(g, prime):
 print(f"{g} is a generator of Z{prime}*")

def euler_totient(n):
 result = n
 p = 2
 while p * p <= n:
 if n % p == 0:
 while n % p == 0:
 n //= p
 result -= result // p
 p += 1
 if n > 1:
 result -= result // n
 return result

# Examples
print("φ(7) =", euler_totient(7)) # 6 (prime)
print("φ(12) =", euler_totient(12)) # 4
print("φ(17) =", euler_totient(17)) # 16
